1	//! AST-walking evaluator.
2	
3	use mlpl_array::{ArrayError, DenseArray, Shape};
4	use mlpl_autograd::{Tape, Tensor};
5	use mlpl_parser::{Expr, TensorCtorKind};
6	use mlpl_trace::{Trace, TraceEvent, TraceValue};
7	
8	use crate::env::Environment;
9	use crate::error::EvalError;
10	use crate::eval_ops::{
11	    eval_analysis_helper, eval_array_lit, eval_binop, eval_fncall, eval_svg, labeled_shape_of,
12	};
13	use crate::value::Value;
14	
15	/// Evaluate a program (list of statements). Returns the last result as an array.
16	///
17	/// If the final value is a string, returns `EvalError::ExpectedArray`.
18	/// Use `eval_program_value` to handle both arrays and strings.
19	pub fn eval_program(stmts: &[Expr], env: &mut Environment) -> Result<DenseArray, EvalError> {
20	    eval_program_value(stmts, env)?.into_array()
21	}
22	
23	/// Evaluate a program and return the final value (array or string).
24	pub fn eval_program_value(stmts: &[Expr], env: &mut Environment) -> Result<Value, EvalError> {
25	    run_program(stmts, env, None)
26	}
27	
28	/// Evaluate a program with tracing enabled. Returns the final array.
29	pub fn eval_program_traced(
30	    stmts: &[Expr],
31	    env: &mut Environment,
32	    trace: &mut Trace,
33	) -> Result<DenseArray, EvalError> {
34	    run_program(stmts, env, Some(trace))?.into_array()
35	}
36	
37	fn run_program(
38	    stmts: &[Expr],
39	    env: &mut Environment,
40	    mut trace: Option<&mut Trace>,
41	) -> Result<Value, EvalError> {
42	    if stmts.is_empty() {
43	        return Err(EvalError::EmptyInput);
44	    }
45	    let mut result = None;
46	    for stmt in stmts {
47	        result = Some(eval_expr(stmt, env, &mut trace)?);
48	    }
49	    result.ok_or(EvalError::EmptyInput)
50	}
51	
52	pub(crate) fn eval_expr(
53	    expr: &Expr,
54	    env: &mut Environment,
55	    trace: &mut Option<&mut Trace>,
56	) -> Result<Value, EvalError> {
57	    if let Expr::StrLit(s, _) = expr {
58	        return Ok(Value::Str(s.clone()));
59	    }
60	    if let Expr::Ident(name, _) = expr
61	        && let Some(s) = env.get_string(name)
62	    {
63	        return Ok(Value::Str(s.clone()));
64	    }
65	    if let Expr::FnCall { name, args, .. } = expr
66	        && name == "svg"
67	    {
68	        return eval_svg(args, env, trace).map(Value::Str);
69	    }
70	    if let Expr::FnCall { name, args, span } = expr
71	        && name == "grad"
72	    {
73	        let result = crate::grad::eval_grad(args, env)?;
74	        if let Some(t) = trace.as_mut() {
75	            let seq = t.events().len() as u64;
76	            t.push(TraceEvent {
77	                seq,
78	                op: "grad".into(),
79	                span: *span,
80	                inputs: vec![],
81	                output: TraceValue::from_array(&result),
82	            });
83	        }
84	        return Ok(Value::Array(result));
85	    }
86	    if let Expr::FnCall { name, args, .. } = expr {
87	        // Model-constructor dispatch -- each builds a ModelSpec from
88	        // its args and returns Value::Model. Kept as a single match so
89	        // the eval entrypoint stays under its file LOC budget.
90	        let model = match name.as_str() {
91	            "linear" => Some(crate::model_dispatch::eval_linear(args, env)),
92	            "embed" => Some(crate::model_dispatch::eval_embedding(args, env)),
93	            "chain" => Some(crate::model_dispatch::eval_chain(args, env)),
94	            "residual" => Some(crate::model_dispatch::eval_residual(args, env)),
95	            "rms_norm" => Some(crate::model_dispatch::eval_rms_norm(args, env)),
96	            "attention" => Some(crate::model_dispatch::eval_attention(args, env, false)),
97	            "causal_attention" => Some(crate::model_dispatch::eval_attention(args, env, true)),
98	            _ => None,
99	        };
100	        if let Some(m) = model {
101	            return Ok(Value::Model(m?));
102	        }
103	    }
104	    if let Expr::FnCall { name, args, .. } = expr
105	        && let Some(kind) = crate::model_dispatch::activation_kind(name)
106	    {
107	        if !args.is_empty() {
108	            return Err(EvalError::BadArity {
109	                func: name.into(),
110	                expected: 0,
111	                got: args.len(),
112	            });
113	        }
114	        return Ok(Value::Model(crate::model::ModelSpec::Activation(kind)));
115	    }
116	    if let Expr::FnCall { name, args, .. } = expr
117	        && name == "apply"
118	    {
119	        let result = crate::model_dispatch::eval_apply(args, env, trace)?;
120	        return Ok(Value::Array(result));
121	    }
122	    if let Expr::FnCall { name, args, .. } = expr
123	        && name == "reshape_labeled"
124	    {
125	        if args.len() != 3 {
126	            return Err(EvalError::BadArity {
127	                func: "reshape_labeled".into(),
128	                expected: 3,
129	                got: args.len(),
130	            });
131	        }
132	        let Expr::ArrayLit(label_elems, _) = &args[2] else {
133	            return Err(EvalError::Unsupported(
134	                "reshape_labeled: third argument must be a bracketed list of string literals"
135	                    .into(),
136	            ));
137	        };
138	        let mut labels: Vec<Option<String>> = Vec::with_capacity(label_elems.len());
139	        for e in label_elems {
140	            let Expr::StrLit(s, _) = e else {
141	                return Err(EvalError::Unsupported(
142	                    "reshape_labeled: axis names must be string literals".into(),
143	                ));
144	            };
145	            labels.push(Some(s.clone()));
146	        }
147	        let source = eval_expr(&args[0], env, trace)?.into_array()?;
148	        let shape_arr = eval_expr(&args[1], env, trace)?.into_array()?;
149	        let dims: Vec<usize> = shape_arr.data().iter().map(|&d| d as usize).collect();
150	        let reshaped = source.reshape(Shape::new(dims))?;
151	        let labeled = reshaped.with_labels(labels)?;
152	        return Ok(Value::Array(labeled));
153	    }
154	    if let Expr::FnCall { name, args, .. } = expr
155	        && let Some(r) = crate::tokenizer::dispatch(name, args, env, trace)
156	    {
157	        return r;
158	    }
159	    if let Expr::FnCall { name, args, .. } = expr
160	        && name == "compare"
161	    {
162	        return crate::experiment::dispatch_compare(args, env);
163	    }
164	    if let Expr::FnCall { name, args, .. } = expr
165	        && (name == "load" || name == "load_preloaded")
166	    {
167	        if args.len() != 1 {
168	            return Err(EvalError::BadArity {
169	                func: name.clone(),
170	                expected: 1,
171	                got: args.len(),
172	            });
173	        }
174	        let Expr::StrLit(path, _) = &args[0] else {
175	            return Err(EvalError::Unsupported(format!(
176	                "{name}: argument must be a string literal"
177	            )));
178	        };
179	        return if name == "load" {
180	            crate::loader::eval_load(env, path)
181	        } else {
182	            crate::loader::eval_load_preloaded(path)
183	        };
184	    }
185	    if let Expr::FnCall { name, args, .. } = expr
186	        && name == "cross_entropy"
187	        && args.len() == 2
188	    {
189	        let logits = eval_expr(&args[0], env, trace)?.into_array()?;
190	        let targets = eval_expr(&args[1], env, trace)?.into_array()?;
191	        crate::model_tape::validate_cross_entropy_targets(&logits, &targets)?;
192	        let result = mlpl_runtime::call_builtin("cross_entropy", vec![logits, targets])?;
193	        return Ok(Value::Array(result));
194	    }
195	    if let Expr::FnCall { name, args, span } = expr
196	        && name == "matmul"
197	        && args.len() == 2
198	    {
199	        let l = eval_expr(&args[0], env, trace)?.into_array()?;
200	        let r = eval_expr(&args[1], env, trace)?.into_array()?;
201	        let result = match l.matmul(&r) {
202	            Ok(a) => a,
203	            Err(ArrayError::ShapeMismatch { .. } | ArrayError::LabelMismatch { .. }) => {
204	                return Err(EvalError::ShapeMismatch {
205	                    op: "matmul".into(),
206	                    expected: labeled_shape_of(&l),
207	                    actual: labeled_shape_of(&r),
208	                });
209	            }
210	            Err(e) => return Err(e.into()),
211	        };
212	        if let Some(t) = trace.as_mut() {
213	            let seq = t.events().len() as u64;
214	            t.push(TraceEvent {
215	                seq,
216	                op: "matmul".into(),
217	                span: *span,
218	                inputs: vec![TraceValue::from_array(&l), TraceValue::from_array(&r)],
219	                output: TraceValue::from_array(&result),
220	            });
221	        }
222	        return Ok(Value::Array(result));
223	    }
224	    if let Expr::FnCall { name, args, .. } = expr
225	        && matches!(
226	            name.as_str(),
227	            "reduce_add" | "reduce_mul" | "argmax" | "softmax"
228	        )
229	        && args.len() == 2
230	        && let Expr::StrLit(axis_name, _) = &args[1]
231	    {
232	        let arr = eval_expr(&args[0], env, trace)?.into_array()?;
233	        let labels = arr.labels().ok_or_else(|| {
234	            EvalError::Unsupported(format!(
235	                "{name}: axis name \"{axis_name}\" requires a labeled array"
236	            ))
237	        })?;
238	        let axis = labels
239	            .iter()
240	            .position(|l| l.as_deref() == Some(axis_name.as_str()))
241	            .ok_or_else(|| {
242	                EvalError::Unsupported(format!(
243	                    "{name}: axis name \"{axis_name}\" not found in labels"
244	                ))
245	            })?;
246	        let axis_arr = DenseArray::from_scalar(axis as f64);
247	        let result = mlpl_runtime::call_builtin(name, vec![arr, axis_arr])?;
248	        return Ok(Value::Array(result));
249	    }
250	    if let Expr::FnCall { name, args, .. } = expr
251	        && (name == "label" || name == "relabel")
252	    {
253	        if args.len() != 2 {
254	            return Err(EvalError::BadArity {
255	                func: name.clone(),
256	                expected: 2,
257	                got: args.len(),
258	            });
259	        }
260	        let Expr::ArrayLit(label_elems, _) = &args[1] else {
261	            return Err(EvalError::Unsupported(format!(
262	                "{name}: second argument must be a bracketed list of string literals"
263	            )));
264	        };
265	        let mut labels: Vec<Option<String>> = Vec::with_capacity(label_elems.len());
266	        for e in label_elems {
267	            let Expr::StrLit(s, _) = e else {
268	                return Err(EvalError::Unsupported(format!(
269	                    "{name}: axis names must be string literals"
270	                )));
271	            };
272	            labels.push(Some(s.clone()));
273	        }
274	        let arr = eval_expr(&args[0], env, trace)?.into_array()?;
275	        let labeled = arr.with_labels(labels)?;
276	        return Ok(Value::Array(labeled));
277	    }
278	    if let Expr::FnCall { name, args, .. } = expr
279	        && name == "labels"
280	    {
281	        if args.len() != 1 {
282	            return Err(EvalError::BadArity {
283	                func: "labels".into(),
284	                expected: 1,
285	                got: args.len(),
286	            });
287	        }
288	        let arr = eval_expr(&args[0], env, trace)?.into_array()?;
289	        // Comma-join the per-axis labels, using an empty string for
290	        // positional axes. Saga 11.5 Phase 1 intentionally stops at
291	        // this stringly-typed encoding because MLPL has no
292	        // string-vector literal yet; Phase 2 introduces one alongside
293	        // the `label(x, [...])` builtin and can upgrade this return
294	        // type in lock-step. The current encoding is testable and
295	        // unambiguous for every rank >= 1: a rank-3 positional array
296	        // becomes `",,"`, a labeled rank-2 becomes `"seq,d_k"`, etc.
297	        // Rank-0 and rank-1-positional both render as `""`; the user
298	        // can call `rank(x)` to disambiguate.
299	        let parts: Vec<String> = match arr.labels() {
300	            Some(lbls) => lbls.iter().map(|l| l.clone().unwrap_or_default()).collect(),
301	            None => (0..arr.rank()).map(|_| String::new()).collect(),
302	        };
303	        return Ok(Value::Str(parts.join(",")));
304	    }
305	    if let Expr::FnCall { name, args, span } = expr
306	        && (name == "momentum_sgd" || name == "adam")
307	    {
308	        let result = if name == "momentum_sgd" {
309	            crate::grad::eval_momentum_sgd(args, env)?
310	        } else {
311	            crate::grad::eval_adam(args, env)?
312	        };
313	        if let Some(t) = trace.as_mut() {
314	            let seq = t.events().len() as u64;
315	            t.push(TraceEvent {
316	                seq,
317	                op: name.clone(),
318	                span: *span,
319	                inputs: vec![],
320	                output: TraceValue::from_array(&result),
321	            });
322	        }
323	        return Ok(Value::Array(result));
324	    }
325	    if let Expr::FnCall { name, args, .. } = expr
326	        && let Some(result) = eval_analysis_helper(name, args, env, trace)
327	    {
328	        return result.map(Value::Str);
329	    }
330	    let (op_name, inputs, result) = match expr {
331	        Expr::IntLit(n, _) => ("literal", vec![], DenseArray::from_scalar(*n as f64)),
332	        Expr::FloatLit(f, _) => ("literal", vec![], DenseArray::from_scalar(*f)),
333	        Expr::StrLit(_, _) => unreachable!(),
334	        Expr::Ident(name, _) => {
335	            let r = env
336	                .get(name)
337	                .cloned()
338	                .ok_or_else(|| EvalError::UndefinedVariable(name.clone()))?;
339	            ("ident", vec![], r)
340	        }
341	        Expr::ArrayLit(elems, _) => ("array_lit", vec![], eval_array_lit(elems, env, trace)?),
342	        Expr::UnaryNeg { operand, .. } => {
343	            let val = eval_expr(operand, env, trace)?.into_array()?;
344	            let r = DenseArray::from_scalar(-1.0).apply_binop(&val, |a, b| a * b)?;
345	            ("negate", vec![TraceValue::from_array(&val)], r)
346	        }
347	        Expr::Assign { name, value, .. } => {
348	            let is_param_ctor = matches!(
349	                value.as_ref(),
350	                Expr::TensorCtor {
351	                    kind: TensorCtorKind::Param,
352	                    ..
353	                }
354	            );
355	            let v = eval_expr(value, env, trace)?;
356	            match v {
357	                Value::Model(m) => {
358	                    env.models.insert(name.clone(), m);
359	                    let placeholder = DenseArray::from_scalar(0.0);
360	                    ("assign_model", vec![], placeholder)
361	                }
362	                Value::Tokenizer(t) => {
363	                    env.set_tokenizer(name.clone(), t);
364	                    let placeholder = DenseArray::from_scalar(0.0);
365	                    ("assign_tokenizer", vec![], placeholder)
366	                }
367	                Value::Str(s) => {
368	                    env.set_string(name.clone(), s);
369	                    ("assign_string", vec![], DenseArray::from_scalar(0.0))
370	                }
371	                Value::Array(val) => {
372	                    env.set(name.clone(), val.clone());
373	                    if is_param_ctor {
374	                        env.mark_param(name);
375	                    }
376	                    ("assign", vec![TraceValue::from_array(&val)], val)
377	                }
378	            }
379	        }
380	        Expr::BinOp { op, lhs, rhs, .. } => eval_binop(op, lhs, rhs, env, trace)?,
381	        Expr::FnCall { name, args, .. } => eval_fncall(name, args, env, trace)?,
382	        Expr::TensorCtor { kind, shape, .. } => eval_tensor_ctor(*kind, shape, env, trace)?,
383	        Expr::Repeat { count, body, .. } => eval_repeat(count, body, env, trace)?,
384	        Expr::Train { count, body, .. } => eval_train(count, body, env, trace)?,
385	        Expr::For {
386	            binding,
387	            source,
388	            body,
389	            ..
390	        } => crate::eval_for::eval_for(binding, source, body, env, trace)?,
391	        Expr::Experiment { name, body, .. } => {
392	            crate::experiment::eval_experiment(name, body, env, trace)?
393	        }
394	    };
395	    if let Some(t) = trace.as_mut() {
396	        let seq = t.events().len() as u64;
397	        t.push(TraceEvent {
398	            seq,
399	            op: op_name.into(),
400	            span: expr.span(),
401	            inputs,
402	            output: TraceValue::from_array(&result),
403	        });
404	    }
405	    Ok(Value::Array(result))
406	}
407	
408	fn eval_tensor_ctor(
409	    kind: TensorCtorKind,
410	    shape: &[Expr],
411	    env: &mut Environment,
412	    trace: &mut Option<&mut Trace>,
413	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
414	    let mut dims = Vec::with_capacity(shape.len());
415	    for dim_expr in shape {
416	        let arr = eval_expr(dim_expr, env, trace)?.into_array()?;
417	        if arr.rank() != 0 {
418	            return Err(EvalError::InvalidShapeDim);
419	        }
420	        let v = arr.data()[0];
421	        if v < 0.0 || v.fract() != 0.0 {
422	            return Err(EvalError::InvalidShapeDim);
423	        }
424	        dims.push(v as usize);
425	    }
426	    let zeros = DenseArray::zeros(Shape::new(dims));
427	    // Construct an autograd Tensor on a fresh tape. Step 005 will
428	    // route this through a tape stored in the environment so that
429	    // operations on the resulting array are recorded; for now we
430	    // simply return the underlying zero-initialized array.
431	    let tape = Tape::new();
432	    let _tensor = match kind {
433	        TensorCtorKind::Param => Tensor::param(tape, zeros.clone()),
434	        TensorCtorKind::Tensor => Tensor::leaf(tape, zeros.clone(), false),
435	    };
436	    let op_name = match kind {
437	        TensorCtorKind::Param => "param_ctor",
438	        TensorCtorKind::Tensor => "tensor_ctor",
439	    };
440	    Ok((op_name, vec![], zeros))
441	}
442	
443	fn eval_repeat(
444	    count: &Expr,
445	    body: &[Expr],
446	    env: &mut Environment,
447	    trace: &mut Option<&mut Trace>,
448	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
449	    let n_arr = eval_expr(count, env, trace)?.into_array()?;
450	    if n_arr.rank() != 0 {
451	        return Err(EvalError::InvalidRepeatCount);
452	    }
453	    let n = n_arr.data()[0] as usize;
454	    let mut r = DenseArray::from_scalar(0.0);
455	    for _ in 0..n {
456	        for stmt in body {
457	            r = eval_expr(stmt, env, trace)?.into_array()?;
458	        }
459	    }
460	    Ok(("repeat", vec![], r))
461	}
462	
463	fn eval_train(
464	    count: &Expr,
465	    body: &[Expr],
466	    env: &mut Environment,
467	    trace: &mut Option<&mut Trace>,
468	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
469	    let n_arr = eval_expr(count, env, trace)?.into_array()?;
470	    if n_arr.rank() != 0 {
471	        return Err(EvalError::InvalidRepeatCount);
472	    }
473	    let n = n_arr.data()[0] as usize;
474	    let mut losses: Vec<f64> = Vec::with_capacity(n);
475	    let mut last = DenseArray::from_scalar(0.0);
476	    for i in 0..n {
477	        env.set("step".into(), DenseArray::from_scalar(i as f64));
478	        let mut step_val = DenseArray::from_scalar(0.0);
479	        for stmt in body {
480	            step_val = eval_expr(stmt, env, trace)?.into_array()?;
481	        }
482	        // Capture the body's final value as the per-step loss; if it
483	        // is non-scalar (e.g. a vector), reduce by mean for the loss
484	        // curve so callers can still rely on a scalar history.
485	        let scalar_loss = if step_val.rank() == 0 {
486	            step_val.data()[0]
487	        } else {
488	            let s: f64 = step_val.data().iter().sum();
489	            s / (step_val.data().len().max(1) as f64)
490	        };
491	        losses.push(scalar_loss);
492	        last = step_val;
493	    }
494	    let losses_arr = DenseArray::new(mlpl_array::Shape::new(vec![losses.len()]), losses)
495	        .expect("losses shape matches data");
496	    env.set("last_losses".into(), losses_arr);
497	    Ok(("train", vec![], last))
498	}
