1	//! Evaluation helpers for binops, function calls, and array literals.
2	
3	use mlpl_array::{ArrayError, DenseArray, Shape};
4	use mlpl_core::LabeledShape;
5	use mlpl_parser::{BinOpKind, Expr};
6	use mlpl_trace::{Trace, TraceValue};
7	
8	use crate::env::Environment;
9	use crate::error::EvalError;
10	use crate::eval::eval_expr;
11	use crate::value::Value;
12	
13	pub(crate) fn eval_binop(
14	    op: &BinOpKind,
15	    lhs: &Expr,
16	    rhs: &Expr,
17	    env: &mut Environment,
18	    trace: &mut Option<&mut Trace>,
19	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
20	    let l = eval_expr(lhs, env, trace)?.into_array()?;
21	    let r = eval_expr(rhs, env, trace)?.into_array()?;
22	    let (name, f): (&str, fn(f64, f64) -> f64) = match op {
23	        BinOpKind::Add => ("add", |a, b| a + b),
24	        BinOpKind::Sub => ("sub", |a, b| a - b),
25	        BinOpKind::Mul => ("mul", |a, b| a * b),
26	        BinOpKind::Div => ("div", |a, b| a / b),
27	    };
28	    let inputs = vec![TraceValue::from_array(&l), TraceValue::from_array(&r)];
29	    let result = match l.apply_binop(&r, f) {
30	        Ok(a) => a,
31	        Err(ArrayError::ShapeMismatch { .. } | ArrayError::LabelMismatch { .. }) => {
32	            return Err(EvalError::ShapeMismatch {
33	                op: name.into(),
34	                expected: labeled_shape_of(&l),
35	                actual: labeled_shape_of(&r),
36	            });
37	        }
38	        Err(e) => return Err(e.into()),
39	    };
40	    Ok((name, inputs, result))
41	}
42	
43	/// Snapshot an array's dims + label list as a `LabeledShape`. Unlabeled
44	/// arrays get `None` at every axis. Saga 11.5 Phase 4: used when
45	/// lifting `ArrayError::ShapeMismatch` / `LabelMismatch` into
46	/// `EvalError::ShapeMismatch` at op call sites.
47	pub(crate) fn labeled_shape_of(a: &DenseArray) -> LabeledShape {
48	    let labels = a
49	        .labels()
50	        .map_or_else(|| vec![None; a.rank()], <[_]>::to_vec);
51	    LabeledShape::new(a.shape().dims().to_vec(), labels)
52	}
53	
54	pub(crate) fn eval_fncall(
55	    name: &str,
56	    args: &[Expr],
57	    env: &mut Environment,
58	    trace: &mut Option<&mut Trace>,
59	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
60	    let evaluated: Vec<DenseArray> = args
61	        .iter()
62	        .map(|a| eval_expr(a, env, trace).and_then(Value::into_array))
63	        .collect::<Result<Vec<_>, _>>()?;
64	    let inputs: Vec<TraceValue> = evaluated.iter().map(TraceValue::from_array).collect();
65	    let result = mlpl_runtime::call_builtin(name, evaluated)?;
66	    Ok(("fncall", inputs, result))
67	}
68	
69	pub(crate) fn eval_svg(
70	    args: &[Expr],
71	    env: &mut Environment,
72	    trace: &mut Option<&mut Trace>,
73	) -> Result<String, EvalError> {
74	    if args.len() != 2 && args.len() != 3 {
75	        return Err(EvalError::BadArity {
76	            func: "svg".into(),
77	            expected: 2,
78	            got: args.len(),
79	        });
80	    }
81	    let data = eval_expr(&args[0], env, trace)?.into_array()?;
82	    let type_name = match eval_expr(&args[1], env, trace)? {
83	        Value::Str(s) => s,
84	        Value::Array(_) | Value::Model(_) | Value::Tokenizer(_) => {
85	            return Err(EvalError::ExpectedString);
86	        }
87	    };
88	    let aux = if args.len() == 3 {
89	        Some(eval_expr(&args[2], env, trace)?.into_array()?)
90	    } else {
91	        None
92	    };
93	    Ok(mlpl_viz::render_with_aux(&data, &type_name, aux.as_ref())?)
94	}
95	
96	/// Dispatch high-level analysis helpers from `mlpl_viz`. Returns
97	/// `None` if `name` is not a known helper.
98	pub(crate) fn eval_analysis_helper(
99	    name: &str,
100	    args: &[Expr],
101	    env: &mut Environment,
102	    trace: &mut Option<&mut Trace>,
103	) -> Option<Result<String, EvalError>> {
104	    if !matches!(
105	        name,
106	        "hist" | "scatter_labeled" | "loss_curve" | "confusion_matrix" | "boundary_2d"
107	    ) {
108	        return None;
109	    }
110	    let evaluated: Result<Vec<DenseArray>, EvalError> = args
111	        .iter()
112	        .map(|a| eval_expr(a, env, trace).and_then(Value::into_array))
113	        .collect();
114	    Some(match evaluated {
115	        Ok(arrs) => call_analysis(name, &arrs),
116	        Err(e) => Err(e),
117	    })
118	}
119	
120	fn call_analysis(name: &str, a: &[DenseArray]) -> Result<String, EvalError> {
121	    let bad_arity = |expected: usize| EvalError::BadArity {
122	        func: name.into(),
123	        expected,
124	        got: a.len(),
125	    };
126	    Ok(match name {
127	        "hist" => {
128	            if a.len() != 2 {
129	                return Err(bad_arity(2));
130	            }
131	            if a[1].rank() != 0 {
132	                return Err(EvalError::ExpectedString);
133	            }
134	            mlpl_viz::analysis_hist(&a[0], a[1].data()[0] as usize)?
135	        }
136	        "scatter_labeled" => {
137	            if a.len() != 2 {
138	                return Err(bad_arity(2));
139	            }
140	            mlpl_viz::analysis_scatter_labeled(&a[0], &a[1])?
141	        }
142	        "loss_curve" => {
143	            if a.len() != 1 {
144	                return Err(bad_arity(1));
145	            }
146	            mlpl_viz::analysis_loss_curve(&a[0])?
147	        }
148	        "confusion_matrix" => {
149	            if a.len() != 2 {
150	                return Err(bad_arity(2));
151	            }
152	            mlpl_viz::analysis_confusion_matrix(&a[0], &a[1])?
153	        }
154	        "boundary_2d" => {
155	            if a.len() != 4 {
156	                return Err(bad_arity(4));
157	            }
158	            mlpl_viz::analysis_boundary_2d(&a[0], &a[1], &a[2], &a[3])?
159	        }
160	        _ => unreachable!(),
161	    })
162	}
163	
164	pub(crate) fn eval_array_lit(
165	    elems: &[Expr],
166	    env: &mut Environment,
167	    trace: &mut Option<&mut Trace>,
168	) -> Result<DenseArray, EvalError> {
169	    if elems.is_empty() {
170	        return Ok(DenseArray::from_vec(vec![]));
171	    }
172	    let evaluated: Vec<DenseArray> = elems
173	        .iter()
174	        .map(|e| eval_expr(e, env, trace).and_then(Value::into_array))
175	        .collect::<Result<Vec<_>, _>>()?;
176	    if evaluated.iter().all(|a| a.rank() == 0) {
177	        let data: Vec<f64> = evaluated.iter().map(|a| a.data()[0]).collect();
178	        return Ok(DenseArray::from_vec(data));
179	    }
180	    let inner_shape = evaluated[0].shape().clone();
181	    let rows = evaluated.len();
182	    let mut data = Vec::with_capacity(rows * inner_shape.elem_count());
183	    for arr in &evaluated {
184	        data.extend_from_slice(arr.data());
185	    }
186	    let mut dims = vec![rows];
187	    dims.extend_from_slice(inner_shape.dims());
188	    Ok(DenseArray::new(Shape::new(dims), data)?)
189	}
