94	/// `chain(layer_a, layer_b, ...)`. Each argument must evaluate to a
95	/// `Value::Model`.
96	pub(crate) fn eval_chain(args: &[Expr], env: &mut Environment) -> Result<ModelSpec, EvalError> {
97	    let mut children = Vec::with_capacity(args.len());
98	    for (i, arg) in args.iter().enumerate() {
99	        match crate::eval::eval_expr(arg, env, &mut None)? {
100	            Value::Model(m) => children.push(m),
101	            _ => {
102	                return Err(EvalError::Unsupported(format!(
103	                    "chain: argument {i} did not evaluate to a model"
104	                )));
105	            }
106	        }
107	    }
108	    Ok(ModelSpec::Chain(children))
109	}
