215	/// `apply(model_ident, X)`.
216	pub(crate) fn eval_apply(
217	    args: &[Expr],
218	    env: &mut Environment,
219	    trace: &mut Option<&mut Trace>,
220	) -> Result<DenseArray, EvalError> {
221	    if args.len() != 2 {
222	        return Err(EvalError::BadArity {
223	            func: "apply".into(),
224	            expected: 2,
225	            got: args.len(),
226	        });
227	    }
228	    let model_name = match &args[0] {
229	        Expr::Ident(n, _) => n.clone(),
230	        _ => {
231	            return Err(EvalError::Unsupported(
232	                "apply: first argument must be a model identifier".into(),
233	            ));
234	        }
235	    };
236	    let model = env
237	        .get_model(&model_name)
238	        .cloned()
239	        .ok_or_else(|| EvalError::UndefinedVariable(model_name.clone()))?;
240	    let x = crate::eval::eval_expr(&args[1], env, trace)?.into_array()?;
241	    apply_model(&model, &x, env)
242	}
