244	fn apply_model(
245	    model: &ModelSpec,
246	    x: &DenseArray,
247	    env: &Environment,
248	) -> Result<DenseArray, EvalError> {
249	    match model {
250	        ModelSpec::Linear { w, b } => {
251	            let w_arr = env
252	                .get(w)
253	                .ok_or_else(|| EvalError::UndefinedVariable(w.clone()))?;
254	            let b_arr = env
255	                .get(b)
256	                .ok_or_else(|| EvalError::UndefinedVariable(b.clone()))?;
257	            let xw = x.matmul(w_arr)?;
258	            // Broadcast b ([1, out]) up to [n, out] via ones([n, 1]) @ b.
259	            let n = xw.shape().dims()[0];
260	            let ones = DenseArray::new(Shape::new(vec![n, 1]), vec![1.0; n])?;
261	            let b_broadcast = ones.matmul(b_arr)?;
262	            Ok(xw.apply_binop(&b_broadcast, |a, c| a + c)?)
263	        }
264	        ModelSpec::Chain(children) => {
265	            let mut cur = x.clone();
266	            for child in children {
267	                cur = apply_model(child, &cur, env)?;
268	            }
269	            Ok(cur)
270	        }
271	        ModelSpec::Activation(kind) => match kind {
272	            ActKind::Tanh => Ok(x.map(f64::tanh)),
273	            ActKind::Relu => Ok(x.map(|v| if v > 0.0 { v } else { 0.0 })),
274	            ActKind::Softmax => Ok(mlpl_runtime::call_builtin(
275	                "softmax",
276	                vec![x.clone(), DenseArray::from_scalar(1.0)],
277	            )?),
278	        },
279	        ModelSpec::Residual(inner) => {
280	            let inner_out = apply_model(inner, x, env)?;
281	            if inner_out.shape() != x.shape() {
282	                return Err(EvalError::Unsupported(
283	                    "residual: inner block must preserve input shape".into(),
284	                ));
285	            }
286	            Ok(x.apply_binop(&inner_out, |a, b| a + b)?)
287	        }
288	        ModelSpec::RmsNorm { .. } => apply_rms_norm(x),
289	        ModelSpec::Attention {
290	            wq,
291	            wk,
292	            wv,
293	            wo,
294	            d_model,
295	            heads,
296	            causal,
297	        } => apply_attention(x, wq, wk, wv, wo, *d_model, *heads, *causal, env),
298	        ModelSpec::Embedding { table, vocab, .. } => {
299	            let t = env
300	                .get(table)
301	                .ok_or_else(|| EvalError::UndefinedVariable(table.clone()))?;
302	            Ok(tokens_to_onehot(x, *vocab)?.matmul(t)?)
303	        }
304	    }
305	}
