307	/// Convert an integer-valued token id array (1-D `[N]`) into a
308	/// `[N, vocab]` one-hot matrix. Token ids must be non-negative
309	/// integers in `[0, vocab)`. The one-hot trick lets the embedding
310	/// gather lower to a plain matmul, so the existing autograd tape
311	/// can backprop into the table without a new gather primitive.
312	fn tokens_to_onehot(tokens: &DenseArray, vocab: usize) -> Result<DenseArray, EvalError> {
313	    let dims = tokens.shape().dims();
314	    if dims.len() != 1 {
315	        return Err(EvalError::Unsupported(format!(
316	            "embed: tokens must be a 1-D [N] array, got shape {dims:?}"
317	        )));
318	    }
319	    let n = dims[0];
320	    let mut data = vec![0.0_f64; n * vocab];
321	    for (row, &id_f) in tokens.data().iter().enumerate() {
322	        if !id_f.is_finite() || id_f < 0.0 || id_f.fract() != 0.0 {
323	            return Err(EvalError::Unsupported(format!(
324	                "embed: token at position {row} = {id_f} is not a non-negative integer"
325	            )));
326	        }
327	        let id = id_f as usize;
328	        if id >= vocab {
329	            return Err(EvalError::Unsupported(format!(
330	                "embed: token at position {row} = {id} out of vocab range [0, {vocab})"
331	            )));
332	        }
333	        data[row * vocab + id] = 1.0;
334	    }
335	    DenseArray::new(Shape::new(vec![n, vocab]), data)
336	        .map_err(|e| EvalError::Unsupported(format!("embed: one-hot construction failed: {e}")))
337	}
