339	#[allow(clippy::too_many_arguments)]
340	fn apply_attention(
341	    x: &DenseArray,
342	    wq: &str,
343	    wk: &str,
344	    wv: &str,
345	    wo: &str,
346	    d_model: usize,
347	    heads: usize,
348	    causal: bool,
349	    env: &Environment,
350	) -> Result<DenseArray, EvalError> {
351	    let dims = x.shape().dims();
352	    if dims.len() != 2 || dims[1] != d_model {
353	        return Err(EvalError::Unsupported(format!(
354	            "attention: input must be [seq, {d_model}], got {:?}",
355	            dims
356	        )));
357	    }
358	    let seq = dims[0];
359	    let d_k = d_model / heads;
360	
361	    let wq_a = env
362	        .get(wq)
363	        .ok_or_else(|| EvalError::UndefinedVariable(wq.into()))?;
364	    let wk_a = env
365	        .get(wk)
366	        .ok_or_else(|| EvalError::UndefinedVariable(wk.into()))?;
367	    let wv_a = env
368	        .get(wv)
369	        .ok_or_else(|| EvalError::UndefinedVariable(wv.into()))?;
370	    let wo_a = env
371	        .get(wo)
372	        .ok_or_else(|| EvalError::UndefinedVariable(wo.into()))?;
373	
374	    let q = x.matmul(wq_a)?;
375	    let k = x.matmul(wk_a)?;
376	    let v = x.matmul(wv_a)?;
377	
378	    let scale = 1.0 / (d_k as f64).sqrt();
379	    // Per-head attention. Concatenate per-head outputs back into a
380	    // [seq, d_model] matrix in the same column layout as the input.
381	    let mut concat = vec![0.0_f64; seq * d_model];
382	    for h in 0..heads {
383	        let q_h = slice_cols(&q, h * d_k, d_k)?;
384	        let k_h = slice_cols(&k, h * d_k, d_k)?;
385	        let v_h = slice_cols(&v, h * d_k, d_k)?;
386	        let scores = q_h.matmul(&k_h.transpose())?;
387	        let scaled: Vec<f64> = scores
388	            .data()
389	            .iter()
390	            .enumerate()
391	            .map(|(i, s)| {
392	                if causal && i % seq > i / seq {
393	                    -1.0e9
394	                } else {
395	                    s * scale
396	                }
397	            })
398	            .collect();
