1	//! Seeded random built-ins: `random` / `randn` and the Saga 13 sampling
2	//! primitives `sample(logits, temperature, seed)` and `top_k(logits, k)`.
3	
4	use mlpl_array::{DenseArray, Shape};
5	
6	use crate::error::RuntimeError;
7	use crate::prng::Xorshift64;
8	
9	/// Dispatch random built-ins. Returns None if not matched.
10	pub(crate) fn try_call(
11	    name: &str,
12	    args: Vec<DenseArray>,
13	) -> Option<Result<DenseArray, RuntimeError>> {
14	    match name {
15	        "random" => Some(build(name, args, |rng| rng.next_f64())),
16	        "randn" => Some(build(name, args, |rng| rng.next_normal())),
17	        "blobs" => Some(builtin_blobs(name, args)),
18	        "moons" | "circles" => Some(synthetic_2d(name, args)),
19	        "sample" => Some(builtin_sample(name, args)),
20	        "top_k" => Some(builtin_top_k(name, args)),
21	        _ => None,
22	    }
23	}
24	
25	/// `sample(logits, temperature, seed)` — categorical sample from a
26	/// 1-D `[V]` logit vector. Returns a scalar integer token id.
27	///
28	/// Temperature `0.0` collapses to `argmax(logits)` (the most likely
29	/// token). Otherwise the sampling distribution is `softmax(logits /
30	/// temperature)`, drawn via inverse-CDF on a single `Xorshift64`
31	/// uniform. `-inf` logits (the masked entries left by `top_k`) are
32	/// supported because the max-subtraction step makes them go to zero
33	/// after `exp`. The same `(logits, temperature, seed)` always yields
34	/// the same id.
35	fn builtin_sample(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
36	    if args.len() != 3 {
37	        return Err(RuntimeError::ArityMismatch {
38	            func: name.into(),
39	            expected: 3,
40	            got: args.len(),
41	        });
42	    }
43	    if args[0].rank() != 1 {
44	        return Err(RuntimeError::InvalidArgument {
45	            func: name.into(),
46	            reason: format!("logits must be a vector, got rank {}", args[0].rank()),
47	        });
48	    }
49	    if args[1].rank() != 0 || args[2].rank() != 0 {
50	        return Err(RuntimeError::InvalidArgument {
51	            func: name.into(),
52	            reason: "temperature and seed must be scalars".into(),
53	        });
54	    }
55	    let logits = args[0].data();
56	    let temperature = args[1].data()[0];
57	    if temperature < 0.0 {
58	        return Err(RuntimeError::InvalidArgument {
59	            func: name.into(),
60	            reason: format!("temperature must be non-negative, got {temperature}"),
61	        });
62	    }
63	    if logits.is_empty() {
64	        return Err(RuntimeError::InvalidArgument {
65	            func: name.into(),
66	            reason: "logits must be non-empty".into(),
67	        });
68	    }
69	    let raw_seed = args[2].data()[0] as i64 as u64;
70	    Ok(DenseArray::from_scalar(
71	        categorical_sample(logits, temperature, raw_seed) as f64,
72	    ))
73	}
74	
75	/// Pure sampling math behind `sample`. `temperature == 0.0` collapses
76	/// to argmax; otherwise draws via inverse-CDF on a SplitMix64-mixed
77	/// xorshift uniform. The mixing decorrelates adjacent small seeds so
78	/// single-shot sampling is well-distributed.
79	fn categorical_sample(logits: &[f64], temperature: f64, raw_seed: u64) -> usize {
80	    if temperature == 0.0 {
81	        let mut best = 0usize;
82	        let mut bv = logits[0];
83	        for (i, &v) in logits.iter().enumerate().skip(1) {
84	            if v > bv {
85	                bv = v;
86	                best = i;
87	            }
88	        }
89	        return best;
90	    }
91	    let m = logits.iter().copied().fold(f64::NEG_INFINITY, f64::max);
92	    let exps: Vec<f64> = logits
93	        .iter()
94	        .map(|x| ((x - m) / temperature).exp())
95	        .collect();
96	    let z: f64 = exps.iter().sum();
97	    let mut s = raw_seed.wrapping_add(0x9E3779B97F4A7C15);
98	    s = (s ^ (s >> 30)).wrapping_mul(0xBF58476D1CE4E5B9);
99	    s = (s ^ (s >> 27)).wrapping_mul(0x94D049BB133111EB);
100	    s ^= s >> 31;
101	    let mut rng = Xorshift64::new(s);
102	    let u = rng.next_f64() * z;
103	    let mut acc = 0.0_f64;
104	    for (i, &e) in exps.iter().enumerate() {
105	        acc += e;
106	        if u < acc {
107	            return i;
108	        }
109	    }
110	    exps.len() - 1
111	}
112	
113	/// `top_k(logits, k)` — return a `[V]` logit vector with all but the
114	/// top-`k` entries replaced by `-inf`. Pure (no randomness). Composed
115	/// with `sample` to implement top-k sampling: the `-inf` entries
116	/// vanish after softmax. Ties are broken by index (lower wins) so the
117	/// result is deterministic.
118	fn builtin_top_k(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
119	    if args.len() != 2 {
120	        return Err(RuntimeError::ArityMismatch {
121	            func: name.into(),
122	            expected: 2,
123	            got: args.len(),
124	        });
125	    }
126	    if args[0].rank() != 1 {
127	        return Err(RuntimeError::InvalidArgument {
128	            func: name.into(),
129	            reason: format!("logits must be a vector, got rank {}", args[0].rank()),
130	        });
131	    }
132	    if args[1].rank() != 0 {
133	        return Err(RuntimeError::InvalidArgument {
134	            func: name.into(),
135	            reason: "k must be a scalar".into(),
136	        });
137	    }
138	    let logits = args[0].data();
139	    let k_raw = args[1].data()[0];
140	    if k_raw < 1.0 || k_raw.fract() != 0.0 || (k_raw as usize) > logits.len() {
141	        return Err(RuntimeError::InvalidArgument {
142	            func: name.into(),
143	            reason: format!("k must be an integer in 1..={}, got {k_raw}", logits.len()),
144	        });
145	    }
146	    let k = k_raw as usize;
147	    let mut order: Vec<usize> = (0..logits.len()).collect();
148	    order.sort_by(|&a, &b| {
149	        logits[b]
150	            .partial_cmp(&logits[a])
151	            .unwrap_or(std::cmp::Ordering::Equal)
152	            .then(a.cmp(&b))
153	    });
154	    let mut keep = vec![false; logits.len()];
155	    for &i in order.iter().take(k) {
156	        keep[i] = true;
157	    }
158	    let out: Vec<f64> = logits
159	        .iter()
160	        .enumerate()
161	        .map(|(i, &x)| if keep[i] { x } else { f64::NEG_INFINITY })
162	        .collect();
163	    Ok(DenseArray::new(Shape::new(vec![logits.len()]), out)?)
164	}
165	
166	/// Shared implementation for the `moons(seed, n, noise)` and
167	/// `circles(seed, n, noise)` synthetic 2D classification datasets.
168	/// Returns an `[n, 3]` matrix of `[x, y, label]` rows. Labels are
169	/// 0 / 1 in two roughly balanced groups; layout is deterministic
170	/// given `seed`.
171	///
172	/// - `moons`: two interleaving half-circles, the classic
173	///   `make_moons` shape.
174	/// - `circles`: a small inner ring (radius 0.5, label 0) inside a
175	///   larger outer ring (radius 1.0, label 1).
176	fn synthetic_2d(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
177	    if args.len() != 3 {
178	        return Err(RuntimeError::ArityMismatch {
179	            func: name.into(),
180	            expected: 3,
181	            got: args.len(),
182	        });
183	    }
184	    for (i, a) in args.iter().enumerate() {
185	        if a.rank() != 0 {
186	            return Err(RuntimeError::InvalidArgument {
187	                func: name.into(),
188	                reason: format!("argument {i} must be scalar, got rank {}", a.rank()),
189	            });
190	        }
191	    }
192	    let seed = args[0].data()[0] as i64 as u64;
193	    let n = args[1].data()[0] as usize;
194	    let noise = args[2].data()[0];
195	    let n0 = n / 2;
196	    let n1 = n - n0;
197	    let mut rng = Xorshift64::new(seed);
198	    let mut data = Vec::with_capacity(n * 3);
199	    let pi = std::f64::consts::PI;
200	    for k in 0..n {
201	        let label = if k < n0 { 0.0 } else { 1.0 };
202	        let local_n = if k < n0 { n0 } else { n1 };
203	        let local_i = if k < n0 { k } else { k - n0 };
204	        let denom = local_n.max(1) as f64;
205	        let (mut x, mut y) = if name == "moons" {
206	            let theta = pi * (local_i as f64) / denom;
207	            if label == 0.0 {
208	                (theta.cos(), theta.sin())
209	            } else {
210	                (1.0 - theta.cos(), 0.5 - theta.sin())
211	            }
212	        } else {
213	            // circles
214	            let theta = 2.0 * pi * (local_i as f64) / denom;
215	            let r = if label == 0.0 { 0.5 } else { 1.0 };
216	            (r * theta.cos(), r * theta.sin())
217	        };
218	        x += noise * rng.next_normal();
219	        y += noise * rng.next_normal();
220	        data.push(x);
221	        data.push(y);
222	        data.push(label);
223	    }
224	    Ok(DenseArray::new(Shape::new(vec![n, 3]), data)?)
225	}
226	
227	fn builtin_blobs(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
228	    if args.len() != 3 {
229	        return Err(RuntimeError::ArityMismatch {
230	            func: name.into(),
231	            expected: 3,
232	            got: args.len(),
233	        });
234	    }
235	    if args[0].rank() != 0 || args[1].rank() != 0 {
236	        return Err(RuntimeError::InvalidArgument {
237	            func: name.into(),
238	            reason: "seed and n_per_class must be scalars".into(),
239	        });
240	    }
241	    let seed = args[0].data()[0] as i64 as u64;
242	    let n_per_class = args[1].data()[0] as usize;
243	    // centers: Kx2 matrix OR length-2K vector.
244	    let centers = &args[2];
245	    let cdims = centers.shape().dims();
246	    let (k, pairs): (usize, Vec<(f64, f64)>) = match cdims.len() {
247	        2 if cdims[1] == 2 => {
248	            let k = cdims[0];
249	            let mut v = Vec::with_capacity(k);
250	            for i in 0..k {
251	                v.push((centers.data()[i * 2], centers.data()[i * 2 + 1]));
252	            }
253	            (k, v)
254	        }
255	        1 if cdims[0].is_multiple_of(2) => {
256	            let k = cdims[0] / 2;
257	            let mut v = Vec::with_capacity(k);
258	            for i in 0..k {
259	                v.push((centers.data()[i * 2], centers.data()[i * 2 + 1]));
260	            }
261	            (k, v)
262	        }
263	        _ => {
264	            return Err(RuntimeError::InvalidArgument {
265	                func: name.into(),
266	                reason: "centers must be Kx2 matrix or length-2K vector".into(),
267	            });
268	        }
269	    };
270	
271	    let sigma = 0.15;
272	    let total = k * n_per_class;
273	    let mut data = Vec::with_capacity(total * 3);
274	    let mut rng = Xorshift64::new(seed);
275	    for (label, &(cx, cy)) in pairs.iter().enumerate().take(k) {
276	        for _ in 0..n_per_class {
277	            let x = cx + sigma * rng.next_normal();
278	            let y = cy + sigma * rng.next_normal();
279	            data.push(x);
280	            data.push(y);
281	            data.push(label as f64);
282	        }
283	    }
284	    Ok(DenseArray::new(Shape::new(vec![total, 3]), data)?)
285	}
286	
287	fn build(
288	    name: &str,
289	    args: Vec<DenseArray>,
290	    mut draw: impl FnMut(&mut Xorshift64) -> f64,
291	) -> Result<DenseArray, RuntimeError> {
292	    if args.len() != 2 {
293	        return Err(RuntimeError::ArityMismatch {
294	            func: name.into(),
295	            expected: 2,
296	            got: args.len(),
297	        });
298	    }
299	    if args[0].rank() != 0 {
300	        return Err(RuntimeError::InvalidArgument {
301	            func: name.into(),
302	            reason: format!("seed must be scalar, got rank {}", args[0].rank()),
303	        });
304	    }
305	    let seed = args[0].data()[0] as i64 as u64;
306	    let dims: Vec<usize> = args[1].data().iter().map(|&d| d as usize).collect();
307	    let count: usize = dims.iter().product();
308	    let mut rng = Xorshift64::new(seed);
309	    let data: Vec<f64> = (0..count).map(|_| draw(&mut rng)).collect();
310	    Ok(DenseArray::new(Shape::new(dims), data)?)
311	}
