1	//! Saga 13 step 006: end-to-end tiny LM training demo primitives.
2	//!
3	//! This file covers two things:
4	//!
5	//! 1. The `shift_pairs_x` / `shift_pairs_y` builtins that slice a
6	//!    1-D token id array `[N]` into two rank-2 arrays `[B, T]` of
7	//!    input tokens and next-token labels. The slicing rule is
8	//!    contiguous, non-overlapping windows of size `block_size + 1`:
9	//!
10	//!        B = N / (block_size + 1)  (integer division; trailing
11	//!                                    tokens that do not fill a full
12	//!                                    window are dropped)
13	//!        X[b, t] = ids[b * (block_size + 1) + t]
14	//!        Y[b, t] = ids[b * (block_size + 1) + t + 1]
15	//!
16	//! 2. An end-to-end tiny LM training run that wires together
17	//!    every Saga 13 primitive: `embed`, `sinusoidal_encoding`,
18	//!    `causal_attention`, `rms_norm`, `linear`, `cross_entropy`,
19	//!    and `adam`. The acceptance bound is that the final loss is
20	//!    at most 60% of the initial loss.
21	
22	use mlpl_array::{DenseArray, Shape};
23	use mlpl_eval::{Environment, eval_program, eval_program_value};
24	use mlpl_parser::{lex, parse};
25	
26	fn arr(dims: Vec<usize>, data: Vec<f64>) -> DenseArray {
27	    DenseArray::new(Shape::new(dims), data).unwrap()
28	}
29	
30	fn run(src: &str, env: &mut Environment) -> DenseArray {
31	    eval_program(&parse(&lex(src).unwrap()).unwrap(), env).unwrap()
32	}
33	
34	// -- shift_pairs_x / shift_pairs_y --
35	
36	#[test]
37	fn shift_pairs_x_returns_block_sized_rows() {
38	    // ids = [0..12], block_size = 3 -> window = 4, B = 12 / 4 = 3.
39	    let mut env = Environment::new();
40	    env.set(
41	        "ids".into(),
42	        DenseArray::from_vec((0..12).map(|i| i as f64).collect()),
43	    );
44	    let out = run("shift_pairs_x(ids, 3)", &mut env);
45	    assert_eq!(out.shape().dims(), &[3, 3]);
46	    assert_eq!(out.data(), &[0.0, 1.0, 2.0, 4.0, 5.0, 6.0, 8.0, 9.0, 10.0]);
47	}
48	
49	#[test]
50	fn shift_pairs_y_returns_next_token_labels() {
51	    // Same ids, same block_size -- Y is X shifted by one inside each window.
52	    let mut env = Environment::new();
53	    env.set(
54	        "ids".into(),
55	        DenseArray::from_vec((0..12).map(|i| i as f64).collect()),
56	    );
57	    let out = run("shift_pairs_y(ids, 3)", &mut env);
58	    assert_eq!(out.shape().dims(), &[3, 3]);
59	    assert_eq!(out.data(), &[1.0, 2.0, 3.0, 5.0, 6.0, 7.0, 9.0, 10.0, 11.0]);
60	}
61	
62	#[test]
63	fn shift_pairs_drops_trailing_tokens_that_cannot_fill_a_window() {
64	    // ids = [0..10], block_size = 3 -> window = 4, B = 10 / 4 = 2.
65	    // Tokens 8, 9 are dropped.
66	    let mut env = Environment::new();
67	    env.set(
68	        "ids".into(),
69	        DenseArray::from_vec((0..10).map(|i| i as f64).collect()),
70	    );
71	    let out_x = run("shift_pairs_x(ids, 3)", &mut env);
72	    let out_y = run("shift_pairs_y(ids, 3)", &mut env);
73	    assert_eq!(out_x.shape().dims(), &[2, 3]);
74	    assert_eq!(out_y.shape().dims(), &[2, 3]);
75	    assert_eq!(out_x.data(), &[0.0, 1.0, 2.0, 4.0, 5.0, 6.0]);
76	    assert_eq!(out_y.data(), &[1.0, 2.0, 3.0, 5.0, 6.0, 7.0]);
77	}
78	
79	#[test]
80	fn shift_pairs_errors_when_ids_too_short() {
81	    // Fewer ids than block_size + 1 means B = 0: empty batch axis,
82	    // which has no training signal. We require at least one window.
83	    let mut env = Environment::new();
84	    env.set("ids".into(), DenseArray::from_vec(vec![0.0, 1.0, 2.0]));
85	    let result = eval_program(
86	        &parse(&lex("shift_pairs_x(ids, 4)").unwrap()).unwrap(),
87	        &mut env,
