118	// -- end-to-end tiny LM --
119	
120	#[test]
121	fn tiny_shakespeare_snippet_is_preloaded() {
122	    // The corpus the demo uses must be compiled into the web REPL
123	    // binary as a preloaded corpus so `load_preloaded("...")` works
124	    // in a WASM context with no filesystem.
125	    let mut env = Environment::new();
126	    let val = eval_program_value(
127	        &parse(&lex("load_preloaded(\"tiny_shakespeare_snippet\")").unwrap()).unwrap(),
128	        &mut env,
