// ---- generation determinism ----

#[test]
fn generation_is_deterministic_on_fixed_seed() {
    // Train a tiny model, then generate twice with the same seed.
    // The two outputs must be byte-identical.
    let setup = "\
        corpus = \"abcabcabcabcabcabcabcabcabcabcabcabc\"\n\
        ids    = tokenize_bytes(corpus)\n\
        X_all  = shift_pairs_x(ids, 8)\n\
        Y_all  = shift_pairs_y(ids, 8)\n\
        X      = reshape(X_all, [reduce_mul(shape(X_all))])\n\
        Y      = reshape(Y_all, [reduce_mul(shape(Y_all))])\n\
        V      = 256 ; d = 8\n\
        model  = chain(embed(V, d, 0), \
                       residual(chain(rms_norm(d), causal_attention(d, 1, 1))), \
                       rms_norm(d), \
                       linear(d, V, 4))\n\
        train 20 { \
          adam(cross_entropy(apply(model, X), Y), model, 0.05, 0.9, 0.999, 0.00000001); \
          cross_entropy(apply(model, X), Y) \
        }";
    let gen = "\
        prompt = tokenize_bytes(\"abc\")\n\
        gen    = prompt\n\
        repeat 10 { \
          logits = apply(model, gen); \
          last   = last_row(logits); \
          nxt    = sample(top_k(last, 40), 0.8, step); \
          gen    = concat(gen, nxt) \
        }\n\
        gen";

    let mut env1 = Environment::new();
    run(setup, &mut env1);
    let out1 = run(gen, &mut env1);

    let mut env2 = Environment::new();
    run(setup, &mut env2);
    let out2 = run(gen, &mut env2);

    assert_eq!(out1.shape(), out2.shape(), "shapes must match");
    assert_eq!(out1.data(), out2.data(), "data must match byte-for-byte");
    // prompt was 3 tokens, generated 10 more => 13 total
    assert_eq!(out1.shape().dims(), &[13]);
}

// ---- attention_weights ----

#[test]
fn attention_weights_are_lower_triangular_for_causal() {
    let mut env = Environment::new();
    let src = "\
        d = 4 ; h = 1\n\
        model = causal_attention(d, h, 42)\n\
        X = randn(7, [5, 4])\n\
        attention_weights(model, X)";
    let weights = run(src, &mut env);
    // Single head => [T, T] = [5, 5]
    assert_eq!(weights.shape().dims(), &[5, 5]);
    let t = 5;
    for r in 0..t {
        for c in 0..t {
            let v = weights.data()[r * t + c];
            if c > r {
                // Above diagonal must be zero (or near-zero after softmax
                // of -1e9)
                assert!(
                    v.abs() < 1e-6,
                    "weight[{r},{c}] = {v} should be ~0 above diagonal"
                );
            }
        }
        // Each row must sum to ~1 (softmax output)
        let row_sum: f64 = (0..t).map(|c| weights.data()[r * t + c]).sum();
        assert!(
            (row_sum - 1.0).abs() < 1e-5,
            "row {r} sum = {row_sum}, expected ~1.0"
        );
    }
}

#[test]
fn attention_weights_non_causal_has_nonzero_above_diagonal() {
    let mut env = Environment::new();
    let src = "\
        d = 4 ; h = 1\n\
        model = attention(d, h, 42)\n\
        X = randn(7, [3, 4])\n\
        attention_weights(model, X)";
    let weights = run(src, &mut env);
    assert_eq!(weights.shape().dims(), &[3, 3]);
    // At least one above-diagonal entry should be non-trivially > 0
    let has_nonzero = (0..3)
        .flat_map(|r| (r + 1..3).map(move |c| (r, c)))
        .any(|(r, c)| weights.data()[r * 3 + c] > 0.01);
    assert!(has_nonzero, "non-causal attention should have nonzero above-diagonal entries");
}

//! Math and constructor built-in functions.

use mlpl_array::{DenseArray, Shape};

use crate::error::RuntimeError;

/// Dispatch math and constructor built-ins. Returns None if not matched.
pub(crate) fn try_call(
    name: &str,
    args: Vec<DenseArray>,
) -> Option<Result<DenseArray, RuntimeError>> {
    match name {
        "exp" => Some(unary(name, args, f64::exp)),
        "log" => Some(unary(name, args, f64::ln)),
        "sqrt" => Some(unary(name, args, f64::sqrt)),
        "abs" => Some(unary(name, args, f64::abs)),
        "sigmoid" => Some(unary(name, args, |x| 1.0 / (1.0 + (-x).exp()))),
        "tanh_fn" => Some(unary(name, args, f64::tanh)),
        "pow" => Some(binary_pow(name, args)),
        "gt" => Some(binary_cmp(name, args, |a, b| if a > b { 1.0 } else { 0.0 })),
        "lt" => Some(binary_cmp(name, args, |a, b| if a < b { 1.0 } else { 0.0 })),
        "eq" => Some(binary_cmp(name, args, |a, b| {
            if (a - b).abs() < f64::EPSILON {
                1.0
            } else {
                0.0
            }
        })),
        "mean" => Some(builtin_mean(name, args)),
        "zeros" | "ones" | "fill" => Some(constructor(name, args)),
        "cosine_schedule" | "linear_warmup" => Some(schedule(name, args)),
        _ => None,
    }
}

fn unary(name: &str, args: Vec<DenseArray>, f: fn(f64) -> f64) -> Result<DenseArray, RuntimeError> {
    if args.len() != 1 {
        return Err(RuntimeError::ArityMismatch {
            func: name.into(),
            expected: 1,
            got: args.len(),
        });
    }
    Ok(args[0].map(f))
}

fn binary_pow(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    if args.len() != 2 {
        return Err(RuntimeError::ArityMismatch {
            func: name.into(),
            expected: 2,
            got: args.len(),
        });
    }
    Ok(args[0].apply_binop(&args[1], f64::powf)?)
}

fn binary_cmp(
    name: &str,
    args: Vec<DenseArray>,
    f: fn(f64, f64) -> f64,
) -> Result<DenseArray, RuntimeError> {
    if args.len() != 2 {
        return Err(RuntimeError::ArityMismatch {
            func: name.into(),
            expected: 2,
            got: args.len(),
        });
    }
    Ok(args[0].apply_binop(&args[1], f)?)
}

fn builtin_mean(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    if args.len() != 1 {
        return Err(RuntimeError::ArityMismatch {
            func: name.into(),
            expected: 1,
            got: args.len(),
        });
    }
    let data = args[0].data();
    let sum: f64 = data.iter().sum();
    let count = data.len().max(1) as f64;
    Ok(DenseArray::from_scalar(sum / count))
}

/// Pure scalar learning-rate schedule built-ins.
///
/// - `cosine_schedule(step, total, lr_min, lr_max)`:
///   `lr_min + 0.5*(lr_max - lr_min)*(1 + cos(pi * step/total))`,
///   clamped to `[lr_min, lr_max]` for `step` outside `[0, total]`.
/// - `linear_warmup(step, warmup, lr)`:
///   `lr * min(1, step/warmup)`, clamped to `[0, lr]`.
fn schedule(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    let expected = if name == "cosine_schedule" { 4 } else { 3 };
    if args.len() != expected {
        return Err(RuntimeError::ArityMismatch {
            func: name.into(),
            expected,
            got: args.len(),
        });
    }
    for (i, a) in args.iter().enumerate() {
        if a.rank() != 0 {
            return Err(RuntimeError::InvalidArgument {
                func: name.into(),
                reason: format!("argument {i} must be a scalar, got rank {}", a.rank()),
            });
        }
    }
    let v = if name == "cosine_schedule" {
        let step = args[0].data()[0];
        let total = args[1].data()[0];
        let lr_min = args[2].data()[0];
        let lr_max = args[3].data()[0];
        if total <= 0.0 {
            lr_max
        } else {
            let t = step.clamp(0.0, total) / total;
            lr_min + 0.5 * (lr_max - lr_min) * (1.0 + (std::f64::consts::PI * t).cos())
        }
    } else {
        let step = args[0].data()[0];
        let warmup = args[1].data()[0];
        let lr = args[2].data()[0];
        if warmup <= 0.0 {
            lr
        } else {
            lr * (step / warmup).clamp(0.0, 1.0)
        }
    };
    Ok(DenseArray::from_scalar(v))
}

fn constructor(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    if name == "fill" {
        if args.len() != 2 {
            return Err(RuntimeError::ArityMismatch {
                func: name.into(),
                expected: 2,
                got: args.len(),
            });
        }
        if args[1].rank() != 0 {
            return Err(RuntimeError::InvalidArgument {
                func: name.into(),
                reason: "value must be scalar".into(),
            });
        }
        let dims: Vec<usize> = args[0].data().iter().map(|&d| d as usize).collect();
        let count = dims.iter().product();
        Ok(DenseArray::new(
            Shape::new(dims),
            vec![args[1].data()[0]; count],
        )?)
    } else {
        if args.len() != 1 {
            return Err(RuntimeError::ArityMismatch {
                func: name.into(),
                expected: 1,
                got: args.len(),
            });
        }
        let dims: Vec<usize> = args[0].data().iter().map(|&d| d as usize).collect();
        let val = if name == "zeros" { 0.0 } else { 1.0 };
        let count = dims.iter().product();
        Ok(DenseArray::new(Shape::new(dims), vec![val; count])?)
    }
}

