/// Compute just the softmax attention weights (no value multiply).
/// Returns `[T, T]` for single-head or `[heads, T, T]` for multi-head.
#[allow(clippy::too_many_arguments)]
fn compute_attn_weights(
    x: &DenseArray,
    wq: &str,
    wk: &str,
    d_model: usize,
    heads: usize,
    causal: bool,
    env: &Environment,
) -> Result<DenseArray, EvalError> {
    let dims = x.shape().dims();
    if dims.len() != 2 || dims[1] != d_model {
        return Err(EvalError::Unsupported(format!(
            "attention_weights: input must be [seq, {d_model}], got {:?}",
            dims
        )));
    }
    let seq = dims[0];
    let d_k = d_model / heads;
    let wq_a = env.get(wq).ok_or_else(|| EvalError::UndefinedVariable(wq.into()))?;
    let wk_a = env.get(wk).ok_or_else(|| EvalError::UndefinedVariable(wk.into()))?;
    let q = x.matmul(wq_a)?;
    let k = x.matmul(wk_a)?;
    let scale = 1.0 / (d_k as f64).sqrt();
    let map_err = |e| EvalError::Unsupported(format!("attention_weights: {e}"));
    let mut all = Vec::with_capacity(heads * seq * seq);
    for h in 0..heads {
        let q_h = slice_cols(&q, h * d_k, d_k)?;
        let k_h = slice_cols(&k, h * d_k, d_k)?;
        let scaled: Vec<f64> = q_h.matmul(&k_h.transpose())?.data().iter().enumerate()
            .map(|(i, s)| if causal && i % seq > i / seq { -1e9 } else { s * scale })
            .collect();
        let attn = mlpl_runtime::call_builtin(
            "softmax", vec![DenseArray::new(Shape::new(vec![seq, seq]), scaled)?,
                            DenseArray::from_scalar(1.0)],
        ).map_err(map_err)?;
        all.extend_from_slice(attn.data());
    }
    let out_shape = if heads == 1 { vec![seq, seq] } else { vec![heads, seq, seq] };
    DenseArray::new(Shape::new(out_shape), all).map_err(map_err)
}

