        let k_h = slice_cols(&k, h * d_k, d_k)?;
        let scaled: Vec<f64> = q_h.matmul(&k_h.transpose())?.data().iter().enumerate()
            .map(|(i, s)| if causal && i % seq > i / seq { -1e9 } else { s * scale })
            .collect();
        let attn = mlpl_runtime::call_builtin(
            "softmax", vec![DenseArray::new(Shape::new(vec![seq, seq]), scaled)?,
                            DenseArray::from_scalar(1.0)],
        ).map_err(map_err)?;
        all.extend_from_slice(attn.data());
    }
    let out_shape = if heads == 1 { vec![seq, seq] } else { vec![heads, seq, seq] };
    DenseArray::new(Shape::new(out_shape), all).map_err(map_err)
}

