134	pub(crate) fn eval_attention(
135	    args: &[Expr],
136	    env: &mut Environment,
137	    causal: bool,
138	) -> Result<ModelSpec, EvalError> {
139	    let func = if causal {
140	        "causal_attention"
141	    } else {
142	        "attention"
