176	        let arr = DenseArray::new(Shape::new(vec![d_model, d_model]), scaled)?;
177	        env.set_param((*name).clone(), arr);
178	    }
179	    Ok(ModelSpec::Attention {
180	        wq,
181	        wk,
182	        wv,
183	        wo,
184	        d_model,
185	        heads,
186	        causal,
187	    })
188	}
