17	/// `linear(in_dim, out_dim, seed)`.
18	pub(crate) fn eval_linear(args: &[Expr], env: &mut Environment) -> Result<ModelSpec, EvalError> {
19	    if args.len() != 3 {
20	        return Err(EvalError::BadArity {
21	            func: "linear".into(),
22	            expected: 3,
23	            got: args.len(),
24	        });
25	    }
26	    let in_dim = scalar_usize(&args[0], env, "linear")?;
27	    let out_dim = scalar_usize(&args[1], env, "linear")?;
28	    let seed = scalar_f64(&args[2], env, "linear")?;
29	
30	    let id = env.next_model_id;
31	    env.next_model_id += 1;
32	    let w_name = format!("__linear_W_{id}");
33	    let b_name = format!("__linear_b_{id}");
34	
35	    // W <- randn(seed, [in_dim, out_dim]) * 0.5 (Xavier-ish small).
36	    let w_init = mlpl_runtime::call_builtin(
37	        "randn",
38	        vec![
39	            DenseArray::from_scalar(seed),
40	            DenseArray::new(Shape::new(vec![2]), vec![in_dim as f64, out_dim as f64])?,
41	        ],
42	    )?;
43	    let w_data: Vec<f64> = w_init.data().iter().map(|v| v * 0.5).collect();
44	    let w = DenseArray::new(Shape::new(vec![in_dim, out_dim]), w_data)?;
45	    env.set_param(w_name.clone(), w);
46	
47	    let b = DenseArray::zeros(Shape::new(vec![1, out_dim]));
48	    env.set_param(b_name.clone(), b);
49	
50	    Ok(ModelSpec::Linear {
51	        w: w_name,
52	        b: b_name,
53	    })
54	}
