56	/// `embed(vocab_size, d_model, seed)` -- token embedding layer.
57	/// Allocates a single `[vocab, d_model]` lookup table parameter,
58	/// initialised with `randn(seed, [vocab, d_model]) * 0.1` (small to
59	/// avoid blowing up early softmax logits in language-model demos).
60	pub(crate) fn eval_embedding(args: &[Expr], env: &mut Environment) -> Result<ModelSpec, EvalError> {
61	    if args.len() != 3 {
62	        return Err(EvalError::BadArity {
63	            func: "embed".into(),
64	            expected: 3,
65	            got: args.len(),
66	        });
67	    }
68	    let vocab = scalar_usize(&args[0], env, "embed")?;
69	    let d_model = scalar_usize(&args[1], env, "embed")?;
70	    let seed = scalar_f64(&args[2], env, "embed")?;
71	
72	    let id = env.next_model_id;
73	    env.next_model_id += 1;
74	    let table_name = format!("__embed_E_{id}");
75	
76	    let table_init = mlpl_runtime::call_builtin(
77	        "randn",
78	        vec![
79	            DenseArray::from_scalar(seed),
80	            DenseArray::new(Shape::new(vec![2]), vec![vocab as f64, d_model as f64])?,
81	        ],
82	    )?;
83	    let table_data: Vec<f64> = table_init.data().iter().map(|v| v * 0.1).collect();
84	    let table = DenseArray::new(Shape::new(vec![vocab, d_model]), table_data)?;
85	    env.set_param(table_name.clone(), table);
86	
87	    Ok(ModelSpec::Embedding {
88	        table: table_name,
89	        vocab,
90	        d_model,
91	    })
92	}
