111	/// `residual(inner_model)`. Wraps a single model argument in a
112	/// skip-connection node.
113	pub(crate) fn eval_residual(args: &[Expr], env: &mut Environment) -> Result<ModelSpec, EvalError> {
114	    if args.len() != 1 {
115	        return Err(EvalError::BadArity {
116	            func: "residual".into(),
117	            expected: 1,
118	            got: args.len(),
119	        });
120	    }
121	    match crate::eval::eval_expr(&args[0], env, &mut None)? {
122	        Value::Model(m) => Ok(ModelSpec::Residual(Box::new(m))),
123	        _ => Err(EvalError::Unsupported(
124	            "residual: argument must evaluate to a model".into(),
125	        )),
126	    }
127	}
