129	/// `attention(d_model, heads, seed)` -- multi-head self-attention.
130	/// `causal_attention(...)` dispatches through the same builder with
131	/// `causal = true`; the parameter set, names, and initial values are
132	/// identical for the same seed, and only the forward pass differs
133	/// (causal_attention applies a lower-triangular mask before softmax).
134	pub(crate) fn eval_attention(
135	    args: &[Expr],
136	    env: &mut Environment,
137	    causal: bool,
138	) -> Result<ModelSpec, EvalError> {
139	    let func = if causal {
140	        "causal_attention"
141	    } else {
142	        "attention"
143	    };
144	    if args.len() != 3 {
145	        return Err(EvalError::BadArity {
146	            func: func.into(),
147	            expected: 3,
148	            got: args.len(),
149	        });
150	    }
151	    let d_model = scalar_usize(&args[0], env, func)?;
152	    let heads = scalar_usize(&args[1], env, func)?;
153	    let seed = scalar_f64(&args[2], env, func)?;
154	    if heads == 0 || d_model % heads != 0 {
155	        return Err(EvalError::Unsupported(format!(
156	            "{func}: d_model ({d_model}) must be divisible by heads ({heads})"
157	        )));
158	    }
159	    let id = env.next_model_id;
160	    env.next_model_id += 1;
161	    let wq = format!("__attn_Wq_{id}");
162	    let wk = format!("__attn_Wk_{id}");
163	    let wv = format!("__attn_Wv_{id}");
164	    let wo = format!("__attn_Wo_{id}");
165	    // Use a small offset on the seed so the four projections do not
166	    // start out identical.
167	    for (i, name) in [&wq, &wk, &wv, &wo].iter().enumerate() {
168	        let init = mlpl_runtime::call_builtin(
169	            "randn",
170	            vec![
171	                DenseArray::from_scalar(seed + i as f64),
172	                DenseArray::new(Shape::new(vec![2]), vec![d_model as f64, d_model as f64])?,
173	            ],
174	        )?;
175	        let scaled: Vec<f64> = init.data().iter().map(|v| v * 0.5).collect();
176	        let arr = DenseArray::new(Shape::new(vec![d_model, d_model]), scaled)?;
177	        env.set_param((*name).clone(), arr);
178	    }
179	    Ok(ModelSpec::Attention {
180	        wq,
181	        wk,
182	        wv,
183	        wo,
184	        d_model,
185	        heads,
186	        causal,
187	    })
188	}
